// Builds styles.css from the static UI CSS in styles.css.base plus the
// per-template CSS generated by src/templates/gallery.ts.
//
// Each template's styles consist of shared BASE_STYLES plus template-specific
// rules. For the light-DOM export path we need those styles available globally
// via styles.css, so this script scopes the shared base under the template's
// card class name and appends the template-specific rules unchanged.

import { readFileSync, writeFileSync } from 'fs';
import { templates } from '../src/templates/gallery.ts';

const BASE_FILE = 'styles.css.base';
const OUT_FILE = 'styles.css';

function scopeTemplateStyles(template) {
  const baseMarker = ':host { display: block; background: transparent; }';
  const raw = template.styles;

  // The first part of every template's styles is BASE_STYLES; the rest is
  // template-specific (including the .${className} rule). Strip the :host rule
  // and wrap the base selectors under the template's card class.
  const baseStart = raw.indexOf(baseMarker);
  if (baseStart === -1) {
    throw new Error(`Template "${template.name}" is missing expected :host rule`);
  }

  const baseEnd = raw.indexOf(`.${template.cardClassName} {`);
  if (baseEnd === -1) {
    throw new Error(`Template "${template.name}" is missing its card class rule`);
  }

  const baseStyles = raw.slice(baseStart + baseMarker.length, baseEnd).trim();
  const templateStyles = raw.slice(baseEnd);

  return [
    `.${template.cardClassName} {`,
    baseStyles,
    '}',
    templateStyles,
  ].join('\n');
}

const baseCss = readFileSync(BASE_FILE, 'utf-8');
const generated = templates.map(scopeTemplateStyles).join('\n\n');
const out = `${baseCss.trim()}\n\n/* Auto-generated template styles — do not edit by hand */\n\n${generated}\n`;
writeFileSync(OUT_FILE, out);

console.error(`Wrote ${OUT_FILE} (${(out.length / 1024).toFixed(1)}KB) from ${templates.length} templates`);
